<?php
 namespace WPAICG\Chat\Admin\Ajax\Traits; use WP_Error; use WPAICG\AIPKit_Role_Manager; if (!defined('ABSPATH')) { exit; } trait Trait_CheckModuleAccess { protected function check_module_access_permissions(string $module_slug, string $nonce_action = 'aipkit_nonce'): bool|WP_Error { if (!check_ajax_referer($nonce_action, '_ajax_nonce', false)) { return new WP_Error('nonce_failure', __('Security check failed (nonce).', 'gpt3-ai-content-generator'), ['status' => 403]); } if (!AIPKit_Role_Manager::user_can_access_module($module_slug)) { return new WP_Error('permission_denied', __('You do not have permission to perform this action.', 'gpt3-ai-content-generator'), ['status' => 403]); } return true; } }